request.query:
BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?view ?name WHERE {
  ?pkg vocab:NamedElement_name "TMT-APS-SE" .
  ?pkg vocab:Element_ownedElement+ ?view .
  ?view rdf:type vocab:view .
  OPTIONAL { ?view vocab:NamedElement_name ?name }
}
ORDER BY ?name

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?view ?name ?qname WHERE {
  ?view rdf:type vocab:view .
  OPTIONAL { ?view vocab:NamedElement_name ?name }
  OPTIONAL { ?view vocab:NamedElement_qualifiedName ?qname }
  FILTER(CONTAINS(LCASE(STR(?qname)), LCASE("APS-SE")))
}
ORDER BY ?name
LIMIT 50
